         var content = $"Report: {reportName}\nGenerated: {utcNow:O}\nMachine: {Environment.MachineName}";

         File.WriteAllText(reportPath, content);
         Console.WriteLine($"Report written to {reportPath}");

         return reportPath;
     }
 }
